SELECT COUNT(*)
FROM incident_migrations
WHERE migrated_county = 'St. Lucie';

SELECT migrated_county
FROM incident_migrations
WHERE migration_reason = 'Due to severity of the incident';

SELECT COUNT(*) AS notification_count
FROM incident_notifications
WHERE agency = 'EPA';

SELECT notification_id, incident_id, agency, notification_date_time
FROM incident_notifications
WHERE agency = 'FDEP';

SELECT COUNT(*) AS total_completed_cleanups
FROM incident_cleanup
WHERE cleanup_status = 'completed';

SELECT document_name, document_type
FROM incident_documents
WHERE strftime('%Y', upload_date_time) = '2023';

SELECT start_date_time, end_date_time, cleanup_status
FROM incident_cleanup
WHERE cleanup_id < 2;
